import React from 'react';
import { Link, useParams } from 'react-router-dom';
import { Helmet } from 'react-helmet-async';

export default function OrderConfirmation() {
  const { id } = useParams();
  const shortId = id ? String(id).slice(-8) : '—';

  return (
    <main className="section container text-center" id="main-content" style={{ padding: '4rem 1rem' }}>
      <Helmet>
        <title>Order confirmed | Nova Shop</title>
      </Helmet>
      <div className="animate-in">
        <div style={{ fontSize: '3rem', marginBottom: '1rem' }} aria-hidden="true">
          ✓
        </div>
        <h1 style={{ marginBottom: '0.75rem' }}>Thank you for your order</h1>
        <p style={{ color: 'var(--gray)', marginBottom: '2rem' }}>
          Order reference <strong>#{shortId}</strong>
        </p>
        <Link to="/account/orders" className="btn btn-primary" style={{ marginRight: '0.75rem' }}>
          View orders
        </Link>
        <Link to="/shop" className="btn btn-outline">
          Continue shopping
        </Link>
      </div>
    </main>
  );
}
